mapper.update:
UPDATE game_question SET question = #{question}, category = #{category}, options = #{options}, answer = #{answer}, difficulty = #{difficulty}, explanation = #{explanation}, status = #{status}, update_time = NOW()
, remark = #{remark}
WHERE id = #{id}

